1	type Customer = {
2	  yearsAsCustomer: number;
3	  quoteCount: number;
4	};
5	
6	type Item = {
7	  type: string;
8	  material: string;
9	  enchantment: number;
10	  cursed: boolean;
11	};
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_RATE = 0.1;
24	const CURSED_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
26	const HIGH_ENCHANTMENT_THRESHOLD = 5;
27	const LOYALTY_DISCOUNT_RATE = 0.2;
28	const LOYALTY_YEARS_THRESHOLD = 2;
29	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
30	
31	const COMPONENT_BLOCK_SIZE = 3;
32	const COMPONENT_BLOCK_PREMIUM = 60;
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	
35	const componentPremium = (type: string, count: number): number =>
36	  count === COMPONENT_BLOCK_SIZE
37	    ? COMPONENT_BLOCK_PREMIUM
38	    : count * BASE_PREMIUMS[type];
39	
40	const itemSurcharge = (item: Item, basePremium: number): number =>
41	  (item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0) +
42	  (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
43	
44	const loyaltyDiscount = (customer: Customer, basePremium: number): number =>
45	  customer.yearsAsCustomer >= LOYALTY_YEARS_THRESHOLD
46	    ? basePremium * LOYALTY_DISCOUNT_RATE
47	    : 0;
48	
49	const followUpDiscount = (customer: Customer, basePremium: number): number =>
50	  customer.quoteCount >= 1
51	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
52	    : 0;
53	
54	export function quote(customer: Customer, items: Item[]): number {
55	  if (items.length === 0) return PROCESSING_FEE;
56	
57	  let basePremium = 0;
58	  let totalItemSurcharges = 0;
59	  const componentCounts: Record<string, number> = {};
60	
61	  for (const item of items) {
62	    if (COMPONENT_TYPES.has(item.type)) {
63	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
64	    } else {
65	      const itemBase = BASE_PREMIUMS[item.type];
66	      basePremium += itemBase;
67	      totalItemSurcharges += itemSurcharge(item, itemBase);
68	    }
69	  }
70	
71	  for (const type of Object.keys(componentCounts)) {
72	    basePremium += componentPremium(type, componentCounts[type]);
73	  }
74	
75	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
76	  const loyalty = loyaltyDiscount(customer, basePremium);
77	  const followUp = followUpDiscount(customer, basePremium);
78	
79	  const totalPremium =
80	    basePremium +
81	    totalItemSurcharges +
82	    firstInsuranceSurcharge -
83	    loyalty -
84	    followUp;
85	
86	  return Math.ceil(totalPremium + PROCESSING_FEE);
87	}
88	
89	export function claim() {
90	  return undefined;
91	}
